mapper.select:
SELECT COUNT(*)
  FROM esg.tb_legal_review
 WHERE comp_id = #{compId}
   AND write_year = #{writeYear}
   AND use_yn = 'Y'

SELECT COUNT(A.*)
  FROM esg.tb_corrective_action_request A
 WHERE A.comp_id = #{compId}
   AND A.write_year = #{writeYear}
   AND A.use_yn = 'Y'
   AND A.car_type='I'

SELECT COUNT(A.*)
  FROM esg.tb_training_plan_annual A
 WHERE A.comp_id = #{compId}
   AND A.write_year = #{writeYear}
   AND A.use_yn = 'Y'

SELECT COUNT(CASE WHEN A.assessment_compl_date IS NOT NULL AND A.assessment_compl_date != '' THEN 1 END) AS registered_cnt,
       COUNT(CASE WHEN A.assessment_compl_date IS NULL OR A.assessment_compl_date = '' THEN 1 END) AS unregistered_cnt
  FROM esg.tb_risk_assessment_plan A
 WHERE A.write_year = #{writeYear}
   AND A.comp_id = #{compId}
   AND A.use_yn = 'Y'

select exists (
    select 1
    from esg.tb_company_info t1
    where t1.use_yn = 'Y'
        and t1.comp_id = #{compId}
) as is_exist
